import java.util.*;
import java.util.function.Function;
import java.util.stream.Collectors;

public class HackathonWinner {

    public static String hackathonWinner(String erica, String bob) {

        // Score mapping
        Map<Character, Integer> points = new HashMap<>();
        points.put('E', 1);
        points.put('M', 3);
        points.put('H', 5);

        // Function to calculate score using streams
        Function<String, Integer> calculateScore = s ->
                s.chars()
                 .map(c -> points.get((char) c))
                 .sum();

        int ericaScore = calculateScore.apply(erica);
        int bobScore = calculateScore.apply(bob);

        return ericaScore > bobScore ? "Erica"
             : bobScore > ericaScore ? "Bob"
             : "Tie";
    }

    public static void main(String[] args) {
        System.out.println(hackathonWinner("EHH", "EME")); // Erica
    }
}

public static String hackathonWinner(String erica, String bob) {

    java.util.function.Function<String, Integer> score = s ->
        s.chars().map(c -> c == 'E' ? 1 : c == 'M' ? 3 : 5).sum();

    return Integer.compare(score.apply(erica), score.apply(bob)) > 0 ? "Erica" :
           Integer.compare(score.apply(erica), score.apply(bob)) < 0 ? "Bob" :
           "Tie";
}
